css:
.slide .eyebrow { font-family: 'Hanken Grotesk', 'Noto Sans KR', sans-serif; }
/* 모든 슬라이드 상단 헤어라인 + 모노그램 chrome */
.slide[data-layout="CONTENT"]::before, .slide[data-layout="STAT"]::before, .slide[data-layout="CARDS"]::before, .slide[data-layout="TABLE"]::before, .slide[data-layout="CALLOUT"]::before, .slide[data-layout="COMPARE"]::before {
  content: ""; position: absolute; left: var(--pad-x); right: var(--pad-x); top: 56px; height: 2px; background: var(--ink); opacity: 0.22;
}
.slide thead th { background: var(--accent); }
.stat-value { font-family: var(--font-display); }
/* SECTION: 큰 세리프 + 얇은 룰 */
.slide[data-layout="SECTION"] .rule { height: 3px; background: var(--accent); }
.slide[data-layout="CLOSING"] { background: var(--surface-dark); }
.slide[data-layout="CLOSING"] .subtitle { color: rgba(239,231,212,0.8); }
